// evolution_hostinger: TUDO fromMe=true — NÃO filtrar por fromMe
const raw = $input.first().json;
const body = raw?.body || raw;

const event = body?.event || "";
const data  = body?.data  || {};
const key   = data?.key   || {};
const msg   = data?.message || {};

if (event && event !== "messages.upsert") {
  return [{ json: { _skip: true, motivo: "evento-ignorado:" + event } }];
}

const remoteJid = key?.remoteJid || "";
const isGroup   = remoteJid.endsWith("@g.us");
if (isGroup) return [{ json: { _skip: true, motivo: "grupo" } }];

const numero    = remoteJid.split("@")[0].replace(/[^0-9]/g, "");
const nome      = data?.pushName || "Cliente";
const messageId = key?.id || "";
const sessionId = remoteJid;

const mensagem = (
  msg?.conversation ||
  msg?.extendedTextMessage?.text ||
  msg?.imageMessage?.caption ||
  msg?.videoMessage?.caption ||
  ""
).trim();

if (!numero || !mensagem) return [{ json: { _skip: true, motivo: "sem-conteudo" } }];

// Filtro de eco: todas as mensagens do bot têm estas assinaturas
const BOT_SIGS = ["🏛️", "© 2026", "👤 *Atendimento", "Atendimento encerrado"];
if (BOT_SIGS.some(s => mensagem.includes(s))) {
  return [{ json: { _skip: true, motivo: "eco-bot" } }];
}

// Dedup via Supabase: pula messageId já processado
if (messageId) {
  const SUPA_URL = "https://qcfdssnpjzvjbvemhrik.supabase.co";
  const SUPA_KEY = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InFjZmRzc25wanp2amJ2ZW1ocmlrIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc4MTcwMzQ3OSwiZXhwIjoyMDk3Mjc5NDc5fQ.1492WOIw4KpT4u57zx-DyT-5O8gEawkWWtjUXMWA2-I";
  try {
    const resp = await this.helpers.httpRequest({
      method: "GET",
      url: `${SUPA_URL}/rest/v1/interacoes_whatsapp?message_id=eq.${messageId}&select=id&limit=1`,
      headers: { "apikey": SUPA_KEY, "Authorization": `Bearer ${SUPA_KEY}` }
    });
    if (Array.isArray(resp) && resp.length > 0) {
      return [{ json: { _skip: true, motivo: "duplicado" } }];
    }
  } catch(e) { /* falha silenciosa: processa mesmo assim */ }
}

const msgLower    = mensagem.toLowerCase().replace(/[!.?]+$/, "").trim();
const STOP_WORDS  = ["parar","stop","sair","cancelar"];
// Reset explícito: SEMPRE vai ao menu, independente de área salva
const EXPLICIT_RESETS = ["menu","inicio","início","voltar","reiniciar"];
// Saudações: levam ao menu SOMENTE se cliente não tiver área salva
const GREETING_WORDS  = ["oi","ola","olá","bom dia","boa tarde","boa noite","hello","hi"];
const MENU_OPCOES = {"1":"b2b","2":"academico","3":"observatorio","4":"api","5":"juridico","6":"filosofia","0":"humano"};

const isStop    = STOP_WORDS.includes(msgLower);
const isReset   = EXPLICIT_RESETS.includes(msgLower);
const isGreeting = GREETING_WORDS.some(g => msgLower === g || msgLower.startsWith(g + " "));

return [{ json: { _skip: false, numero, nome, mensagem, msgLower, sessionId, messageId,
  isStop, isReset, isGreeting,
  opcaoMenu: MENU_OPCOES[msgLower] || null } }];

// Busca contato no Supabase — SEMPRE retorna 1 item com { contatos: [...] }
const dadosMsg = $('2. Extrair e Normalizar').first().json;
const { numero } = dadosMsg;
const SUPA_URL = 'https://qcfdssnpjzvjbvemhrik.supabase.co';
const SUPA_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InFjZmRzc25wanp2amJ2ZW1ocmlrIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc4MTcwMzQ3OSwiZXhwIjoyMDk3Mjc5NDc5fQ.1492WOIw4KpT4u57zx-DyT-5O8gEawkWWtjUXMWA2-I';

let contatos = [];
try {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: `${SUPA_URL}/rest/v1/fenice_tim_contatos?numero=eq.${numero}&limit=1`,
    headers: { 'apikey': SUPA_KEY, 'Authorization': `Bearer ${SUPA_KEY}` }
  });
  contatos = Array.isArray(resp) ? resp : [];
} catch(e) {
  contatos = [];
}

return [{ json: { contatos } }];

// ── Decide próximo passo com base no perfil do contato ──
const dadosMsg = $('2. Extrair e Normalizar').first().json;
const contatosArr = ($input.first().json.contatos) || [];
const contato = contatosArr.length > 0 ? contatosArr[0] : null;

const areaAtual = contato ? contato.area : null;
const { isReset, isGreeting, opcaoMenu, numero, nome, mensagem } = dadosMsg;

// Reset EXPLÍCITO (menu/voltar/reiniciar) → sempre vai ao menu
if (isReset) {
  return [{ json: { _acao: 'menu_principal', numero, nome, mensagem, areaAtual: null } }];
}

// Opção de menu escolhida (1-6, 0) → SEMPRE prevalece sobre área salva
if (opcaoMenu) {
  if (opcaoMenu === 'humano') {
    return [{ json: { _acao: 'humano', numero, nome, mensagem, areaAtual: 'humano' } }];
  }
  return [{ json: { _acao: 'set_area', numero, nome, mensagem, areaAtual: opcaoMenu } }];
}

// Saudação de cliente que JÁ TEM área → continua na área (não mostra menu)
if (isGreeting && areaAtual) {
  return [{ json: { _acao: 'responder', numero, nome, mensagem, areaAtual } }];
}

// Saudação SEM área → menu (primeiro contato)
if (isGreeting) {
  return [{ json: { _acao: 'menu_principal', numero, nome, mensagem, areaAtual: null } }];
}

// Sem área e sem opção → menu
if (!areaAtual) {
  return [{ json: { _acao: 'menu_principal', numero, nome, mensagem, areaAtual: null } }];
}

// Tem área, sem nova escolha → responde na área atual
return [{ json: { _acao: 'responder', numero, nome, mensagem, areaAtual } }];

// ── Monta system prompt por área + busca histórico e RAG ──────────
const dados = $('7. Decidir Próxima Ação').first().json;
const { numero, nome, mensagem, areaAtual } = dados;

const SYSTEM_PROMPTS = {
  b2b: `Você é o assistente comercial B2B da Fenice IT Justech.IA, via WhatsApp. Foco: soluções corporativas para escritórios de advocacia e empresas (API jurídica, RAG, planos enterprise, SLA). Seja consultivo e direto. Colete nome, empresa e necessidade. Demonstrou interesse real → ofereça demo: contato@fenice.ia.br. Cliente: ${nome}. © 2026 Fenice IT Justech.IA`,
  academico: `Você é o assistente acadêmico da Fenice IT Justech.IA, via WhatsApp. Auxilia estudantes e professores de direito com pesquisa jurídica, TCC, artigos científicos e análise doutrinária.

BASE DE CONHECIMENTO: 5685 artigos, súmulas do STJ e STF, legislação federal atualizada.

ACESSO PREMIUM: https://fenice.ia.br
Mencione este link quando o usuário fizer a primeira pergunta ou quando precisar de recursos avançados (análise de peças, hermenêutica, geração de TCC).

PRIMEIRO CONTATO: Se a mensagem for um número ou saudação simples, apresente os serviços disponíveis e inclua o link premium.

Seja didático, claro e preciso. Cite a base legal quando relevante.
Cliente: ${nome}. © 2026 Fenice IT Justech.IA`,
  observatorio: `Você é o assistente digital do *Observatório da Mulher de São Francisco do Sul* (Fenice IT Justech.IA), via WhatsApp.

MISSÃO: Apoiar mulheres em situação de vulnerabilidade, violência doméstica ou risco social.

SITE OFICIAL: https://observatorio-da-mulher-sfs.com.br/
Inclua este link SEMPRE na sua primeira resposta para que a pessoa acesse todos os recursos disponíveis.

EMERGÊNCIA — se houver risco imediato à vida, informe IMEDIATAMENTE: ligue 190 (Polícia) ou 180 (Central da Mulher). Não espere por mais informações.

BASE LEGAL: Lei Maria da Penha (Lei 11.340/2006), Lei do Feminicídio (Lei 13.104/2015).

PRIMEIRO CONTATO: Se a mensagem do usuário for um número (como '3') ou uma saudação simples, apresente o Observatório, liste os serviços disponíveis e inclua o link. Seja acolhedor e empático.

Nunca minimize sofrimento. Sempre ofereça o link e os números de emergência quando relevante.
Cliente: ${nome}. © 2026 Fenice IT Justech.IA`,
  api: `Você é o assistente técnico da Fenice IT Justech.IA, para desenvolvedores via WhatsApp. API REST fenice.ia.br — /buscar (Free), /analisar /hermeneutica /tcc (Premium). Auth: X-Fenice-Key. Stack: FastAPI + Supabase + Groq. Seja técnico e preciso. Chaves: contato@fenice.ia.br. Cliente: ${nome}. © 2026 Fenice IT Justech.IA`,
  juridico: `Você é o assistente jurídico da Fenice IT Justech.IA, via WhatsApp. Direito brasileiro: CC, CLT, CP, CF/88, CDC. Seja profissional e objetivo (máx 800 chars). Se incerto → diga que pesquisa. Nunca invente leis. Cliente: ${nome}. © 2026 Fenice IT Justech.IA`,
  filosofia: `Você é o assistente de Filosofia, Teologia e Pensamento da Fenice IT Justech.IA, via WhatsApp. Domínio: filosofia jurídica, hermenêutica, teologia cristã/islâmica/judaica, ética, metafísica. Seja reflexivo e acessível. Cite pensadores relevantes. Cliente: ${nome}. © 2026 Fenice IT Justech.IA`
};

const sistemaPrompt = SYSTEM_PROMPTS[areaAtual] || SYSTEM_PROMPTS.juridico;

// Seleção de área (dígito único) → saudação breve, sem listar opções
const isAreaSelection = /^[0-9]$/.test(mensagem.trim());
const introNote = isAreaSelection
  ? 'INSTRUÇÃO OBRIGATÓRIA: O usuário acabou de selecionar esta área digitando um número. Cumprimente-o com UMA frase breve e pergunte diretamente o que ele precisa. NÃO liste serviços, NÃO crie submenus, NÃO numere opções. Seja conciso.\n\n'
  : '';
const promptFinal = introNote + sistemaPrompt;

const groqBody = JSON.stringify({
  model: 'gemini-2.5-flash',
  messages: [
    { role: 'system', content: promptFinal },
    { role: 'user', content: mensagem }
  ],
  max_tokens: 800,
  temperature: 0.7
});

return [{ json: { numero, nome, mensagem, areaAtual, groqBody } }];

// Debounce: aguarda 6s antes de chamar o Groq
await new Promise(r => setTimeout(r, 6000));
return $input.all();

const groqResult = $input.first().json;
const dadosPrompt = $('10. Montar Prompt por Área').first().json;

const textoGroq = (groqResult.choices && groqResult.choices.length > 0)
  ? groqResult.choices[0].message.content
  : 'Nosso assistente está com alta demanda. Tente em 1 minuto ou: contato@fenice.ia.br';

// Adiciona assinatura para identificar eco do bot no próximo webhook
const respostaAi = textoGroq.includes("🏛️") ? textoGroq : textoGroq + "\n\n🏛️";

return [{
  json: {
    numero: dadosPrompt.numero,
    nome: dadosPrompt.nome,
    mensagem: dadosPrompt.mensagem,
    areaAtual: dadosPrompt.areaAtual,
    respostaAi,
    modeloAi: groqResult.model || 'llama-3.3-70b-versatile'
  }
}];

const evoResult = $input.first().json;
const dadosMsg = $('12. Extrair Resposta Groq').first().json;
const dadosParser = $('2. Extrair e Normalizar').first().json;

const entregue  = evoResult.key?.id ? true : false;
const userMsgId = dadosParser.messageId || '';

const logBody = JSON.stringify({
  message_id: userMsgId,
  numero_remetente: dadosMsg.numero,
  nome_remetente: dadosMsg.nome,
  mensagem_cliente: dadosMsg.mensagem,
  resposta_ai: dadosMsg.respostaAi,
  modelo_ai: dadosMsg.modeloAi,
  provider: 'evolution',
  canal: 'whatsapp',
  entregue
});

const timBody = JSON.stringify({
  numero: dadosMsg.numero,
  nome: dadosMsg.nome,
  area: dadosMsg.areaAtual,
  estagio: 'atendimento',
  ultimo_contato: new Date().toISOString()
});

return [{ json: { logBody, timBody, entregue, userMsgId } }];
